static const u8 *pkm_kunit_synthesize_file_sd(const u8 *parent_sd,
					      size_t parent_sd_len,
					      const u8 *template_sd,
					      size_t template_sd_len,
					      u32 child_is_directory,
					      size_t *len_out)
{
	const u8 *sd = NULL;
	size_t sd_len = 0;

	if (kacs_rust_synthesize_file_sd(parent_sd, parent_sd_len, template_sd,
					 template_sd_len,
					 child_is_directory, &sd,
					 &sd_len) != 0)
		return NULL;

	if (len_out)
		*len_out = sd_len;
	return sd;
}

static const u8 *pkm_kunit_first_dacl_ace_const(const u8 *sd_bytes)
{
	u32 dacl_offset;

	if (!sd_bytes)
		return NULL;

	dacl_offset = pkm_kunit_read_u32(sd_bytes, 16);
	if (dacl_offset == 0)
		return NULL;
	if (pkm_kunit_read_u16(sd_bytes, dacl_offset + 4) == 0)
		return NULL;

	return sd_bytes + dacl_offset + 8;
}

static const u8 *pkm_kunit_first_sacl_ace_const(const u8 *sd_bytes)
{
	u32 sacl_offset;

	if (!sd_bytes)
		return NULL;

	sacl_offset = pkm_kunit_read_u32(sd_bytes, 12);
	if (sacl_offset == 0)
		return NULL;
	if (pkm_kunit_read_u16(sd_bytes, sacl_offset + 4) == 0)
		return NULL;

	return sd_bytes + sacl_offset + 8;
}

static u8 *pkm_kunit_first_dacl_ace(u8 *sd_bytes)
{
	return (u8 *)pkm_kunit_first_dacl_ace_const(sd_bytes);
}

static const u8 *pkm_kunit_first_inherited_dacl_ace_const(const u8 *sd_bytes)
{
	const u8 *ace;
	u32 dacl_offset;
	u16 ace_count;
	u16 i;

	if (!sd_bytes)
		return NULL;

	dacl_offset = pkm_kunit_read_u32(sd_bytes, 16);
	if (dacl_offset == 0)
		return NULL;

	ace_count = pkm_kunit_read_u16(sd_bytes, dacl_offset + 4);
	ace = sd_bytes + dacl_offset + 8;
	for (i = 0; i < ace_count; i++) {
		u16 ace_size = pkm_kunit_read_u16(ace, 2);

		if ((ace[1] & PKM_KUNIT_INHERITED_ACE) != 0)
			return ace;
		if (ace_size == 0)
			return NULL;
		ace += ace_size;
	}

	return NULL;
}

static const u8 *pkm_kunit_first_inherited_sacl_ace_const(const u8 *sd_bytes)
{
	const u8 *ace;
	u32 sacl_offset;
	u16 ace_count;
	u16 i;

	if (!sd_bytes)
		return NULL;

	sacl_offset = pkm_kunit_read_u32(sd_bytes, 12);
	if (sacl_offset == 0)
		return NULL;

	ace_count = pkm_kunit_read_u16(sd_bytes, sacl_offset + 4);
	ace = sd_bytes + sacl_offset + 8;
	for (i = 0; i < ace_count; i++) {
		u16 ace_size = pkm_kunit_read_u16(ace, 2);

		if ((ace[1] & PKM_KUNIT_INHERITED_ACE) != 0)
			return ace;
		if (ace_size == 0)
			return NULL;
		ace += ace_size;
	}

	return NULL;
}

static void pkm_kunit_make_first_file_ace_inheritable(u8 *sd_bytes,
						      u8 inherit_flags)
{
	u8 *ace;

	ace = pkm_kunit_first_dacl_ace(sd_bytes);
	if (!ace)
		return;

	ace[1] = inherit_flags;
}

static void pkm_kunit_make_first_file_ace_mask(u8 *sd_bytes, u32 mask)
{
	u8 *ace;

	ace = pkm_kunit_first_dacl_ace(sd_bytes);
	if (!ace)
		return;

	pkm_kunit_write_u32(ace, 4, mask);
}

static void pkm_kunit_make_first_sacl_ace_inheritable(u8 *sd_bytes,
						      u8 inherit_flags)
{
	u8 *ace;

	ace = (u8 *)pkm_kunit_first_sacl_ace_const(sd_bytes);
	if (!ace)
		return;

	ace[1] = inherit_flags;
}

static void pkm_kunit_make_first_file_ace_opaque(u8 *sd_bytes, u8 ace_flags)
{
	u8 *ace;

	ace = pkm_kunit_first_dacl_ace(sd_bytes);
	if (!ace)
		return;

	ace[0] = PKM_KUNIT_OPAQUE_ACE_TYPE;
	ace[1] = ace_flags;
}

static void pkm_kunit_make_first_file_ace_sid(u8 *sd_bytes, const u8 *sid,
					      size_t sid_len)
{
	u8 *ace;

	if (!sid)
		return;

	ace = pkm_kunit_first_dacl_ace(sd_bytes);
	if (!ace)
		return;
	if (pkm_kunit_read_u16(ace, 2) != 8U + sid_len)
		return;

	memcpy(ace + 8, sid, sid_len);
}

