	struct pkm_kacs_kunit_socket_view target = { };
	long ret;

	ret = pkm_kacs_kunit_unix_dgram_send_for_subject(
		pkm_kacs_current_effective_token_ptr(), 1, 1, &sender,
		&target);
	KUNIT_ASSERT_EQ(test, ret, 0L);
